// gen-devtools-bundle.mjs — bundle the Holo DevTools dock boot into ONE self-contained IIFE and emit it as
// a C++ raw-string header the host ExecuteJavaScript()s into every APP tab's main world. Mirror of
// gen-playground-bundle.mjs. Self-contained = NO module import / NO cross-origin fetch, so it installs
// the dock regardless of OS-closure drift (the failure mode of injecting a <script src=holo://os/…>).
//
//   node tools/gen-devtools-bundle.mjs
//
// Entry = holo-devtools-dock-boot.js (imports dock + ui + keys + live-backend + object/scene/blake3/uor and
// runs as an IIFE side-effect). Output = src/devtools_bundle.h with `const char kHoloDevToolsBundle[]`.
// NOTE: unlike playground, this bundle LEGITIMATELY contains the string "holo://os/_shared/devtools/
// holo-devtools.html" — the URL of the vendored Chrome frontend iframe (a file, not inlineable). We forbid
// dynamic import() (the real self-containment test) but allow that one intentional iframe-URL string.

import { execFileSync } from "node:child_process";
import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const repo = join(here, "..", "..", "..", "..", "..");                 // …/HOLOGRAM
const esbuild = process.platform === "win32"
  ? join(repo, ".ui-build", "node_modules", "@esbuild", "win32-" + (process.arch === "arm64" ? "arm64" : "x64"), "esbuild.exe")
  : join(repo, ".ui-build", "node_modules", ".bin", "esbuild");
const entry = join(repo, "holo-os", "system", "os", "usr", "lib", "holo", "devtools", "holo-devtools-dock-boot.js");
const outJs = join(here, "holo-dt-bundle.gen.js");
const outH = join(here, "..", "src", "devtools_bundle.h");

if (!existsSync(esbuild)) throw new Error("esbuild not found at " + esbuild);
if (!existsSync(entry)) throw new Error("entry not found at " + entry);
execFileSync(esbuild, [entry, "--bundle", "--format=iife", "--minify", "--legal-comments=none", "--outfile=" + outJs], { stdio: "inherit" });

const js = readFileSync(outJs, "utf8");
// Self-containment test: NO dynamic import() (a static holo://os iframe-URL string is allowed by design).
if (/import\s*\(/.test(js)) throw new Error("bundle is NOT self-contained (has dynamic import)");
const D = "HOLODTBUNDLE";
if (js.includes(")" + D + '"')) throw new Error("raw-string delimiter clash");

// MSVC caps a single string literal at 16380 bytes (C2026). Emit as adjacent raw-string literals (<=12 KB),
// never splitting a code point — the compiler concatenates them into one array.
const MAX_BYTES = 12000;
const chunks = [];
let cur = "", curBytes = 0;
for (const ch of js) {
  const b = Buffer.byteLength(ch, "utf8");
  if (curBytes + b > MAX_BYTES && cur) { chunks.push(cur); cur = ""; curBytes = 0; }
  cur += ch; curBytes += b;
}
if (cur) chunks.push(cur);
for (const c of chunks) { if (Buffer.byteLength(c, "utf8") > 16000) throw new Error("chunk exceeds MSVC literal limit"); }
const body = chunks.map((c) => 'R"' + D + "(" + c + ")" + D + '"').join("\n");

const banner = [
  "// devtools_bundle.h - GENERATED by tools/gen-devtools-bundle.mjs. Do not edit by hand.",
  "// The Holo DevTools dock boot as ONE self-contained IIFE (esbuild bundle of holo-devtools-dock-boot.js +",
  "// its graph; no module import / no cross-origin fetch — so it installs the right-docked inspector even if",
  "// the OS closure is mid-reseal). app.cc ExecuteJavaScript()s it into every APP tab's main world.",
  "// Adjacent raw-string chunks (<=12 KB each) to stay under the MSVC C2026 16380-byte literal cap.",
  "#ifndef HOLO_DEVTOOLS_BUNDLE_H",
  "#define HOLO_DEVTOOLS_BUNDLE_H",
  "const char kHoloDevToolsBundle[] =",
].join("\n");
writeFileSync(outH, banner + "\n" + body + ";\n#endif\n");
console.log("wrote " + outH + " (" + js.length + " bytes of JS in " + chunks.length + " literals)");
